const path = require('path');
const _ = require('lodash');

const {Config, environment} = require('webpack-config');

const rootPath = path.join(__dirname, '..');
const srcPath = path.join(rootPath, 'src');

const vendorsPath = path.join(srcPath, 'lib/bx-ui/vendors');

module.exports = env => {

    const jqGridPath = path.join(vendorsPath, 'jquery.jqgrid.src.js');
    const jsTreePath = path.join(vendorsPath, 'jstree.js');
    const jqueryUI = path.join(vendorsPath, 'jquery-ui.js');
    const velocityPath = path.join(vendorsPath, 'velocity.js');
    const velocityUIPath = path.join(vendorsPath, 'velocity.ui.js');

    environment.setAll({config: {
        vendors: [jqGridPath, jsTreePath, jqueryUI, velocityPath, velocityUIPath]
    }});

    return new Config().extend(path.join(__dirname, 'webpack.' + env + '.config.js'));
};